import React from 'react';
import Iframe from 'react-iframe';

function GameIFrame({ title, embed }) {
  // Establece el ancho y alto del iframe para mantener la proporción 1x1 del juego
  const width = '100%';
  const paddingTop = '100%'; // Mantener la proporción 1x1

  window.coi = {
    shouldRegister: () => !reloadedBySelf,
    shouldDeregister: () => false,
    coepCredentialless: () => true,
    coepDegrade: () => true,
    doReload: () => window.location.reload(),
    quiet: false
  }

  return (
    <div className="card" style={{ width: '100%', maxWidth: '600px', margin: 'auto' }}>
      <div className="card-body" style={{ padding: 0 }}>
        <div style={{ position: 'relative', width, paddingTop }}>
          <Iframe
            frameborder="0"
            src={embed}
            title={title}
            width="100%"
            height="100%"
            allowfullscreen=""
            style={{ position: 'absolute', width: '100%', height: '100%' }}
          ></Iframe>
        </div>
      </div>
    </div>
  );
};

export default GameIFrame;
